import React, {useState, useEffect} from "react";
import { useNavigate } from "react-router-dom";
import "./customerservice.css";
import './main.css'
import Navbaremployee from "./upperlistemployee";
import Cookies from "universal-cookie";

export const CustomerService = () => {
    const navigate = useNavigate();
    const handleSubmit = (event) => {
        event.preventDefault();
        // Check if all required fields are filled
        const nameField = event.target.querySelector('[name="name"]');
        const phoneField = event.target.querySelector('[name="phone"]');
        const emailField = event.target.querySelector('[name="email"]');
        const cinemaField = event.target.querySelector('[name="cinema"]');
        const opinionField = event.target.querySelector('[name="opinion"]');
        if (
            nameField.value.trim() === '' ||
            phoneField.value.trim() === '' ||
            emailField.value.trim() === '' ||
            cinemaField.value.trim() === '' ||
            opinionField.value.trim() === ''
        ) {
            alert('Please fill out all fields before submitting.');
            return;
        }
        navigate('/');
    };

    const cinemas = ['cinema1', 'cinema2', 'cinema3'];

    const [search, setSearch] = useState('');
    const cookies=new Cookies();
    useEffect(() => {
        cookies.set('search',search,{path:'/'});
        console.log(cookies)
    },[search])

    const [name, setName] = useState('');
    const [phone, setPhone] = useState('');
    const [email, setEmail] = useState('');
    useEffect(() => {
        setName(cookies.get('name') || '');
        setPhone(cookies.get('tel') || ''); 
        setEmail(cookies.get('email') || '');
    }, [cookies]);

    return(
        <>
            <Navbaremployee setSearch={setSearch}/>
            <div className="blank"/>
            <form className="customerOpinion" onSubmit={handleSubmit}>
                <div className="name">
                    <div className="nameLabel">姓名:</div>
                    <input type="text" value={name} readOnly />
                </div>
                
                <div className="selectSex">
                    <div className="sexLabel">性別:</div>
                    <input type="radio" name="sex" value="male" />男
                    <input type="radio" name="sex" value="female" />女
                </div>

                <div className="inputPhone">
                    <div className="phoneLabel">連絡電話:</div>
                    <input type="tel" value={phone} readOnly />
                </div>

                <div className="inputEmail">
                    <div className="emailLabel">Email:</div>
                    <input type="email" value={email} readOnly />
                </div>
                
                <div className="cinema">
                    <div className="cinemaLabel">建議之影城:</div>
                    <select className="selectCinema" required>
                        {cinemas.map((cinema, index) => (
                            <option key={index} value={cinema}>
                                {cinema}
                            </option>
                        ))}
                    </select>
                </div>

                <div className="opinion">
                    <div className="opinionLabel">建議內容:</div>
                    <input type="text" required />
                </div>

                <button type="submit">送出您的意見</button>
            </form>
        </>
    );
};

export default CustomerService;
